// ── voice / answer_booking_question ──────────────────────────────────────────
// Input: POST body with question (string)
// Queries the knowledge base for relevant articles, or falls back to a
// standard booking information answer.

const SUPABASE_URL = $env.SUPABASE_URL;
const SUPABASE_KEY = $env.SUPABASE_SERVICE_KEY;

const item     = $input.first();
const headers  = item.json.headers || {};
const body     = item.json.body   || {};

const tenantId = (headers['x-tenant-id'] || '').toString().trim();
const question = (body.question || '').toString().trim();

if (!question) {
  return [{ json: { success: false, error: { code: 'VALIDATION_ERROR', message: 'question is required' } } }];
}

// Try to find a relevant knowledge article
let articles = [];
if (SUPABASE_URL && SUPABASE_KEY && tenantId) {
  try {
    const resp = await $helpers.httpRequest({
      method: 'GET',
      url: `${SUPABASE_URL}/rest/v1/knowledge_articles?tenant_id=eq.${tenantId}&status=eq.published&select=title,content&limit=3`,
      headers: {
        'apikey': SUPABASE_KEY,
        'Authorization': `Bearer ${SUPABASE_KEY}`,
      },
    });
    if (Array.isArray(resp)) articles = resp;
  } catch (_) {
    // Ignore DB errors — fall back to static answer
  }
}

let answer;
if (articles.length > 0) {
  // Return content from the first available article
  answer = articles[0].content || articles[0].title;
} else {
  // Static fallback answer
  answer = 'Gerne helfen wir Ihnen bei Ihrer Buchungsanfrage! Sie können online über unsere Website einen Termin buchen oder uns direkt anrufen. Unsere Öffnungszeiten sind Montag bis Freitag von 9 bis 18 Uhr. Bei Fragen zu spezifischen Leistungen und Preisen beraten wir Sie gerne persönlich.';
}

return [{ json: { success: true, answer } }];
